UPDATE model_status


        usage_status = #{updateEntity.usageStatus},


        observation_time = #{updateEntity.observationTime},


        type = #{updateEntity.type},


        start_time = #{updateEntity.startTime},


        end_time = #{updateEntity.endTime},


        update_time = #{updateEntity.updateTime},


WHERE id = (
    SELECT id FROM (
        SELECT id FROM model_status


                model_name = #{condition.modelName}


                AND user_name = #{condition.userName}


                AND create_userid = #{condition.createUserid}


                and observation_time=#{condition.observationTime}


                and start_time=#{condition.startTime}


                and end_time=#{condition.endTime}

            AND status = 0

        ORDER BY id DESC
        LIMIT 1
    ) AS temp
)

